mapper.select:
SELECT r.id, r.reporter_id, r.reported_user_id, r.product_id, r.order_id,
       r.type, r.description, r.evidence_images, r.status, r.resolution,
       r.deleted_at, r.created_at, r.updated_at, r.resolved_at
FROM reports r
WHERE r.deleted_at IS NULL

    AND r.reporter_id = #{reporterId}


    AND r.status = #{status}


    AND r.type = #{type}

ORDER BY r.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM reports r
WHERE r.deleted_at IS NULL

    AND r.reporter_id = #{reporterId}


    AND r.status = #{status}


    AND r.type = #{type}
